def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            base_term = ((-1) ** j) * (ratio ** j) / (j + 0.5)
            if j % 3 == 0:
                base_term *= np.exp(-ratio * j)
            elif j % 2 == 0:
                base_term *= 1.2
            else:
                base_term *= 0.85
            score += base_term
        if capacity < item * 1.1:
            score *= 4
            for k in range(1, 5):
                score += ((-1) ** (k+1)) * np.tanh(ratio ** (k+4)) / (k + 2)
            if ratio > 0.9:
                score += np.log1p(ratio) * np.sin(ratio * 10)
        elif capacity < item * 1.8:
            score *= 2
            for k in range(5):
                score += np.cos(ratio * (k + 2)) / (k + 1.5)
            if ratio < 0.5:
                for m in range(3):
                    score -= np.sqrt(ratio + m / 10) * (m + 1)
        elif capacity > item * 5:
            score /= 4
            for k in range(3, 7):
                score -= np.log1p(ratio * k) / (k + 0.7)
            if ratio < 0.3:
                score += np.exp(-ratio * 5)
        else:
            for k in range(1, 5):
                score += (ratio ** k) * np.cos(k * ratio * 1.5) / (k + 3)
            if np.isclose(score, 0, atol=1e-4):
                score += 0.1
        if score < 0:
            priorities[i] = -score * (1 + np.sin(ratio * np.pi))
        else:
            priorities[i] = np.inf
    return priorities
